patterns.wrong_pattern:
// WRONG: velocity is wiped by reset
const bullet = bullets.get();
if (bullet) {
  bullet.setActive(true).setVisible(true);
  bullet.setVelocityY(-400);   // set velocity first
  bullet.body.reset(player.x, player.y - 20);  // reset wipes it
}

patterns.right_pattern:
// RIGHT: position via reset(), then velocity
const bullet = bullets.get();
if (bullet) {
  bullet.body.reset(player.x, player.y - 20);  // position first
  bullet.setActive(true).setVisible(true);
  bullet.setVelocityY(-400);                    // velocity AFTER reset
  bullet.body.setAllowGravity(false);           // re-assert any flags reset clears
}

patterns.wrong_pattern:
// WRONG: stale body state, sprite visible at old position
const enemy = enemies.get();
enemy.x = spawnX;            // changes sprite x but body stays at old x
enemy.y = spawnY;
enemy.setVelocityX(-100);    // body might still be disabled

patterns.right_pattern:
// RIGHT: enableBody syncs sprite+body+state
const enemy = enemies.get();
if (enemy) {
  enemy.enableBody(true, spawnX, spawnY, true, true); // reset, reposition, show, activate
  enemy.setVelocityX(-100);
}

patterns.wrong_pattern:
// WRONG: container at (200,300), child body is at child's local (10,0)
const container = this.add.container(200, 300);
const sprite = this.physics.add.sprite(10, 0, 'enemy');
container.add(sprite);
// sprite renders at (210,300) but body is at (10,0)

patterns.right_pattern:
// RIGHT (option A): keep Container at 0,0 and offset children
const container = this.add.container(0, 0);
const sprite = this.physics.add.sprite(210, 300, 'enemy');
container.add(sprite);

// RIGHT (option B): don't use Container for physics objects; group them in a Layer or just track them in an array

patterns.wrong_pattern:
// WRONG: child.x is local to container, not world
const playerSprite = container.list[0];
this.cameras.main.startFollow({ x: playerSprite.x, y: playerSprite.y }); // follows wrong point

patterns.right_pattern:
// RIGHT: get world coords via transform matrix
const m = playerSprite.getWorldTransformMatrix();
const worldX = m.tx, worldY = m.ty;
// Or follow the container itself if appropriate:
this.cameras.main.startFollow(container);

patterns.wrong_pattern:
// WRONG: rapid clicks cut each other off
function onClick() {
  this.sound.play('laser');  // re-uses one Sound; cancels previous
}

patterns.right_pattern:
// RIGHT (Web Audio): play() creates a new fire-and-forget instance
// Phaser's Web Audio Sound Manager handles overlap automatically when sound.play(key) is called WITHOUT a stored reference, but reliable pooling looks like:
const sfxPool = Array.from({length: 4}, () => this.sound.add('laser'));
let idx = 0;
function onClick() {
  const s = sfxPool[idx]; idx = (idx + 1) % sfxPool.length;
  if (s.isPlaying) s.stop();
  s.play();
}

// HTML5 fallback: declare instances at load time
this.load.audio('laser', 'laser.mp3', { instances: 4 });

patterns.wrong_pattern:
// WRONG: every restart adds another layer
create() {
  this.sound.play('bgm', { loop: true });
}

patterns.right_pattern:
// RIGHT (option A): stop matching key before play
create() {
  this.sound.stopByKey('bgm');
  this.bgm = this.sound.add('bgm', { loop: true });
  this.bgm.play();
  this.events.once(Phaser.Scenes.Events.SHUTDOWN, () => this.bgm.stop());
}

// RIGHT (option B): persistent music in registry, started once
create() {
  if (!this.registry.get('bgm')) {
    const bgm = this.sound.add('bgm', { loop: true });
    bgm.play();
    this.registry.set('bgm', bgm);
  }
}

patterns.wrong_pattern:
// WRONG: launch leaves GameOverScene + GameScene both active
this.scene.launch('GameOverScene');  // GameScene still updating

// WRONG: never registers cleanup, listeners leak across restarts
create() {
  this.input.keyboard.on('keydown-SPACE', () => this.fire());
}

patterns.right_pattern:
// RIGHT: stop the gameplay scene when transitioning to game-over
this.scene.start('GameOverScene', { score: this.score });

// RIGHT: register cleanup on SHUTDOWN
create() {
  const handler = () => this.fire();
  this.input.keyboard.on('keydown-SPACE', handler);
  this.events.once(Phaser.Scenes.Events.SHUTDOWN, () => {
    this.input.keyboard.off('keydown-SPACE', handler);
  });
}

patterns.wrong_pattern:
// WRONG: condition stays true frame after frame
update() {
  if (this.enemies.countActive() === 0) {
    this.spawnWave();   // fires every frame after wave is cleared
  }
  if (this.time.now - this.lastShotAt > 200) {
    this.fire();        // fires every frame past 200ms
  }
}

patterns.right_pattern:
// RIGHT: re-entry guard flag, set BEFORE starting work
update() {
  if (!this.waveActive && this.enemies.countActive() === 0) {
    this.waveActive = true;          // GUARD set before spawn
    this.time.delayedCall(2000, () => {
      this.spawnWave();
      this.waveActive = false;       // released only after spawn completes
    });
  }
  // For cooldowns, advance the timestamp on the side-effect:
  if (this.time.now - this.lastShotAt > 200) {
    this.lastShotAt = this.time.now; // bump BEFORE firing
    this.fire();
  }
}

patterns.wrong_pattern:
// WRONG: looping tween + timer + listener never cleaned up
create() {
  this.tweens.add({ targets: this.title, alpha: 0.5, yoyo: true, repeat: -1 });
  this.time.addEvent({ delay: 1000, callback: this.tick, loop: true });
  this.registry.events.on('changedata', this.onData, this);
}

patterns.right_pattern:
// RIGHT: own references and tear them down on shutdown
create() {
  this.titleTween = this.tweens.add({ targets: this.title, alpha: 0.5, yoyo: true, repeat: -1 });
  this.tickEvt = this.time.addEvent({ delay: 1000, callback: this.tick, callbackScope: this, loop: true });
  this.registry.events.on('changedata', this.onData, this);

  this.events.once(Phaser.Scenes.Events.SHUTDOWN, () => {
    this.titleTween.stop(); this.titleTween.remove();
    this.tickEvt.remove(false);
    this.registry.events.off('changedata', this.onData, this);
  });
}

patterns.wrong_pattern:
// WRONG: animation defined but frame names don't match the atlas
this.anims.create({
  key: 'walk',
  frames: this.anims.generateFrameNames('hero', { prefix: 'walk_', start: 1, end: 4 }),
  frameRate: 10, repeat: -1
});
sprite.play('walk');  // silent no-op if hero atlas has 'run_1'..'run_4'

patterns.right_pattern:
// RIGHT: verify frame generation, guard play(), and load atlas in a Boot/Preload scene
// In Preload scene:
this.load.atlas('hero', 'hero.png', 'hero.json');

// In Game scene create():
const frames = this.anims.generateFrameNames('hero', { prefix: 'walk_', start: 1, end: 4 });
if (frames.length === 0) {
  console.error('No frames generated for walk anim — check atlas keys');
}
this.anims.create({ key: 'walk', frames, frameRate: 10, repeat: -1 });

// Defensive play:
if (this.anims.exists('walk')) sprite.play('walk');
else sprite.setFrame('walk_1');

patterns.wrong_pattern:
// WRONG: listener added every create(); accumulates across restarts
create() {
  this.input.on('pointerdown', () => this.fire());  // 2 instances after 1 restart, 3 after 2
}

// WRONG: keydown without repeat guard
this.input.keyboard.on('keydown-SPACE', this.fire, this);  // fires on every OS repeat

patterns.right_pattern:
// RIGHT: bind once, clean up on SHUTDOWN
create() {
  this.fireHandler = () => this.fire();
  this.input.on('pointerdown', this.fireHandler);
  this.events.once(Phaser.Scenes.Events.SHUTDOWN, () => {
    this.input.off('pointerdown', this.fireHandler);
  });
}

// RIGHT: use JustDown to fire only on the leading edge
update() {
  if (Phaser.Input.Keyboard.JustDown(this.cursors.space)) this.fire();
}

patterns.wrong_pattern:
// WRONG: undefined score and stale Text reference
class GameScene extends Phaser.Scene {
  create() {
    // this.score never initialized → undefined
    this.scoreText = this.add.text(10, 10, 'Score: ' + this.score);
  }
  hit() {
    this.score += 10;  // undefined + 10 = NaN forever after
    this.scoreText.setText('Score: ' + this.score);
  }
}

// WRONG: external module holds stale text
import { hud } from './hud';
create() { hud.scoreText = this.add.text(...); }  // survives scene.restart with broken ref

patterns.right_pattern:
// RIGHT: explicit init in init(), fresh Text in create()
class GameScene extends Phaser.Scene {
  init(data) {
    this.score = data?.score ?? 0;   // explicit default
  }
  create() {
    this.scoreText = this.add.text(10, 10, `Score: ${this.score}`);
  }
  hit() {
    this.score += 10;
    this.scoreText.setText(`Score: ${this.score}`);  // template literal, never NaN if init guarded
  }
}

patterns.wrong_pattern:
// WRONG: crashes on corrupt data, no version check, no try/catch
const save = JSON.parse(localStorage.getItem('save'));
this.score = save.score;        // TypeError if save is null
this.level = save.level;        // undefined if old schema
localStorage.setItem('save', JSON.stringify(this));  // no quota guard

patterns.right_pattern:
// RIGHT: defensive load with version, defaults, and migration
const CURRENT_VERSION = 2;
const DEFAULT_SAVE = { version: CURRENT_VERSION, score: 0, level: 1, unlocks: [] };

function loadSave() {
  try {
    const raw = localStorage.getItem('save');
    if (!raw) return { ...DEFAULT_SAVE };
    const parsed = JSON.parse(raw);
    return migrate(parsed);
  } catch (e) {
    console.warn('Save corrupt, resetting:', e);
    return { ...DEFAULT_SAVE };
  }
}

function migrate(save) {
  if (!save.version) save = { ...save, version: 1, unlocks: [] }; // v0 -> v1
  if (save.version === 1) save = { ...save, version: 2 };          // v1 -> v2 (no field changes here)
  return { ...DEFAULT_SAVE, ...save };  // fill any missing fields
}

function saveSave(save) {
  try { localStorage.setItem('save', JSON.stringify(save)); }
  catch (e) { console.warn('Save failed (quota or disabled):', e); }
}

