// WRONG: player created before ground layer; player hidden
this.player = this.physics.add.sprite(100, 100, 'hero');
this.groundLayer = map.createLayer('Ground', tileset, 0, 0);
this.foregroundLayer = map.createLayer('Foreground', tileset, 0, 0);
// player is rendered first => behind ground

patterns.right_pattern:
// RIGHT: explicit depths, decoupled from creation order
this.groundLayer = map.createLayer('Ground', tileset, 0, 0).setDepth(0);
this.objectLayer = map.createLayer('Objects', tileset, 0, 0).setDepth(10);
this.player = this.physics.add.sprite(100, 100, 'hero').setDepth(20);
this.foregroundLayer = map.createLayer('Foreground', tileset, 0, 0).setDepth(30);

this.groundLayer.setCollisionByProperty({ collides: true });
this.physics.add.collider(this.player, this.groundLayer);

patterns.wrong_pattern:
// WRONG: only one bounds set; camera scrolls into emptiness
this.physics.world.setBounds(0, 0, 2000, 600);
this.cameras.main.startFollow(player);  // no setBounds, follows into void

patterns.right_pattern:
// RIGHT: both physics world AND camera bounds, plus setCollideWorldBounds
this.physics.world.setBounds(0, 0, 2000, 600);
this.cameras.main.setBounds(0, 0, 2000, 600);
this.cameras.main.startFollow(player, true, 0.1, 0.1);  // lerpX/Y for smoothing
player.setCollideWorldBounds(true);

patterns.wrong_pattern:
// WRONG: listener stacks on every restart
create() {
  this.events.on('damage', this.onDamage, this);
  document.addEventListener('visibilitychange', this.onVisibility);
  this.particles = this.add.particles(0, 0, 'spark', { lifespan: 1000, quantity: 100, frequency: 16 });
  // 100 particles every 16ms forever, no cleanup
}

patterns.right_pattern:
// RIGHT: cleanup, particle quantity sanity, off-pattern with same handler ref
create() {
  this.onDamageBound = this.onDamage.bind(this);
  this.events.on('damage', this.onDamageBound);

  this.onVisibilityBound = () => this.handleVis();
  document.addEventListener('visibilitychange', this.onVisibilityBound);

  this.particles = this.add.particles(0, 0, 'spark', {
    lifespan: 600, quantity: 1, frequency: 50, maxParticles: 50  // cap explicitly
  });

  this.events.once(Phaser.Scenes.Events.SHUTDOWN, () => {
    this.events.off('damage', this.onDamageBound);
    document.removeEventListener('visibilitychange', this.onVisibilityBound);
    this.particles.destroy();
  });
}

patterns.wrong_pattern:
// WRONG: restart loses level state
init(data) {
  this.level = data.level;  // crashes on restart() with no args
}
onDie() { this.scene.restart(); }

patterns.right_pattern:
// RIGHT: data init defensive AND use registry for persistence
init(data = {}) {
  this.level = data.level ?? this.registry.get('level') ?? 1;
  this.registry.set('level', this.level);
}
onDie() { this.scene.restart(); }  // registry survives

