// WRONG: collider added every frame
update() {
  this.physics.add.collider(this.player, this.platforms);  // 60/sec
}

patterns.right_pattern:
// RIGHT: register colliders once in create()
create() {
  this.physics.add.collider(this.player, this.platforms);
  this.physics.add.overlap(this.player, this.coins, this.collectCoin, null, this);
}
